    def add_task(self, task_id, description):
        if task_id in self.tasks:
            raise ValueError(f'Task {task_id} already exists.')
        self.tasks[task_id] = description
        self.dependencies.add_node(task_id)

    def add_dependency(self, task_id, depends_on):
        if task_id not in self.tasks or depends_on not in self.tasks:
            raise ValueError('Both tasks must exist to create a dependency.')
        self.dependencies.add_edge(depends_on, task_id)

    def get_task_order(self):
        """
        Returns the order in which tasks should be completed based on their dependencies.
        :return: list of str, ordered list of task IDs
        :raises: ValueError if a cycle is detected in the task dependencies
        """
        ordered_tasks = []
        visited = set()
        rec_stack = set()

        def dfs(task_id):
            if task_id in rec_stack:
                raise ValueError(f'Cycle detected involving task {task_id}')
            if task_id in visited:
                return
            visited.add(task_id)
            rec_stack.add(task_id)
            for neighbor in self.dependencies.neighbors(task_id):
                dfs(neighbor)
            rec_stack.remove(task_id)
            ordered_tasks.append(task_id)

        for task_id in self.tasks:
            if task_id not in visited:
                dfs(task_id)

        return ordered_tasks[::-1]

    def assign_task(self, task_id, agent):
        if task_id not in self.tasks:
            raise ValueError(f'Task {task_id} does not exist.')
        self.tasks[task_id] = (self.tasks[task_id], agent)

    def mark_task_complete(self, task_id):
        if task_id not in self.tasks:
            raise ValueError(f'Task {task_id} does not exist.')
        self.dependencies.remove_node(task_id)

    def get_task_status(self):
        return self.tasks

    def get_remaining_tasks(self):
        return list(self.dependencies.nodes())
"
}
